-- Trigger to set updated_at on UPDATE
DROP TRIGGER IF EXISTS purchase_orders_update_audit ON buying.purchase_orders;
CREATE TRIGGER purchase_orders_update_audit BEFORE UPDATE ON buying.purchase_orders
    FOR EACH ROW EXECUTE FUNCTION buying.purchase_orders_audit_timestamp();
